const crypto = require('crypto');
const uuidv4 = require('uuid/v4');

class Coupon {
  constructor(code, discount, expirationDate) {
    this.code = code;
    this.discount = discount;
    this.expirationDate = new Date(expirationDate);
    this.used = false;
    this.hash = crypto.createHash('sha256').update(this.code).digest('hex');
  }

  isValid() {
    return !this.used && this.expirationDate > new Date();
  }
}

class CouponSystem {
  constructor() {
    this.coupons = {};
  }

  addCoupon(coupon) {
    const hash = coupon.hash;
    if (!this.coupons[hash]) {
      this.coupons[hash] = coupon;
    } else {
      throw new Error('Coupon already exists');
    }
  }

  redeemCoupon(code, userId) {
    const hash = crypto.createHash('sha256').update(code).digest('hex');
    const coupon = this.coupons[hash];
    if (coupon && coupon.isValid()) {
      if (!coupon.used) {
        coupon.used = true;
        return { discount: coupon.discount };
      } else {
        throw new Error('Coupon has already been used');
      }
    } else {
      throw new Error('Invalid or expired coupon');
    }
  }

  generateCoupon(discount, expirationDate) {
    const code = uuidv4();
    const coupon = new Coupon(code, discount, expirationDate);
    this.addCoupon(coupon);
    return { code };
  }
}

const couponSystem = new CouponSystem();

